SELECT 


 ORDER BY e.rprt_yr DESC, e.eucr_ver DESC, e.frst_reg_dt DESC
 LIMIT #{pageSize} OFFSET #{offset}

SELECT MAX(CAST(SPLIT_PART(eucr_ver, '.', 1) AS INTEGER)) || '.0'
  FROM er.tn_eucr
 WHERE oprtr_id = #{oprtrId}
   AND rprt_yr  = #{rprtYr}

