UPDATE er.tn_eucr
   SET eucr_st_cd       = #{newSt},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE eucr_id = #{eucrId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
